class PeekingIterator:
    def __init__(self, iterator):
        self.vals = []
        while iterator.hasNext():
            self.vals.append(iterator.next())
        self.i = 0
    def peek(self):
        return self.vals[self.i]
    def next(self):
        v = self.vals[self.i]
        self.i += 1
        return v
    def hasNext(self):
        return self.i < len(self.vals)

