class PeekingIterator:
    def __init__(self, iterator):
        self.iterator = iterator
        self.has_buffered = False
        self.buffered = None
    def peek(self):
        if not self.has_buffered:
            self.buffered = self.iterator.next()
            self.has_buffered = True
        return self.buffered
    def next(self):
        if self.has_buffered:
            self.has_buffered = False
            v = self.buffered
            self.buffered = None
            return v
        return self.iterator.next()
    def hasNext(self):
        return self.has_buffered or self.iterator.hasNext()

